import re
from typing import Protocol
from loguru import logger
from .models import DataPayload
from .exceptions import ValidationError, PersistenceError, BusinessLogicError

class Repository(Protocol):
    def save(self, data: DataPayload) -> None: ...

class DataService:
    def __init__(self, repository: Repository) -> None:
        self._repository = repository

    def _sanitize_log(self, data: str) -> str:
        """Prevents log injection by removing newline characters."""
        return re.sub(r'[\r\n]', '', data)

    def process_data(self, raw_data: dict) -> None:
        """
        Orchestrates data processing with granular error handling.
        """
        try:
            payload = DataPayload(**raw_data)
        except Exception as e:
            logger.error(f"Validation failed: {self._sanitize_log(str(e))}")
            raise ValidationError("Invalid input format") from e

        try:
            self._repository.save(payload)
        except (ConnectionError, TimeoutError) as e:
            logger.error("Persistence layer unavailable")
            raise PersistenceError("Database connection failed") from e
        except Exception as e:
            logger.error(f"Unexpected system error: {self._sanitize_log(str(e))}")
            raise BusinessLogicError("An internal processing error occurred")
